class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        long long dp[zero + 1][one + 1];
        memset(dp, 0, sizeof(dp));
        dp[0][0] = 1;
        for (int i = 1; i <= zero; ++i) {
            for (int j = 1; j <= one; ++j) {
                dp[i][j] = (dp[i - 1][j] + dp[i][j - 1]) % (1e9 + 7);
                if (i > 0 && j > 0 && i + j > limit) {
                    dp[i][j] = (dp[i][j] - dp[i - 1][j - 1] + 1e9 + 7) % (1e9 + 7);
                }
            }
        }
        return dp[zero][one];
    }
};
